(function (window) {
    // Minimal DOMPurify-compatible shim. Not a full replacement for DOMPurify,
    // but provides a conservative sanitize(html, config) function so the editor
    // can work offline when the CDN is unavailable.

    if (typeof window === 'undefined') return;
    if (window.DOMPurify) return;

    function isSafeImageDataUrl(val) {
        return /^data:image\/(?:png|jpe?g|gif|webp|bmp|avif);base64,[a-z0-9+\/=\s]+$/i.test(val);
    }

    function sanitizeAttributes(el, allowedAttrs) {
        const attrs = Array.from(el.attributes || []);
        for (const attr of attrs) {
            const name = attr.name.toLowerCase();
            const value = (attr.value || '').trim();

            // Remove event handlers
            if (name.startsWith('on')) {
                el.removeAttribute(attr.name);
                continue;
            }

            // Strip javascript: and unsafe data: URIs (allow safe image data URLs)
            if (/^(javascript|data):/i.test(value) && !(el.tagName && el.tagName.toLowerCase() === 'img' && name === 'src' && isSafeImageDataUrl(value))) {
                el.removeAttribute(attr.name);
                continue;
            }

            // If allowedAttrs provided, enforce it for specific tags
            if (allowedAttrs && allowedAttrs.constructor === Object) {
                const tag = el.tagName.toLowerCase();
                const allowedForTag = allowedAttrs[tag] || [];
                if (allowedForTag.length && !allowedForTag.includes(name) && name !== 'style' && name !== 'class') {
                    el.removeAttribute(attr.name);
                    continue;
                }
            }
        }
    }

    function sanitizeNode(node, allowedTags, allowedAttrs) {
        const toRemove = [];
        for (let i = 0; i < node.childNodes.length; i++) {
            const child = node.childNodes[i];
            if (child.nodeType === Node.ELEMENT_NODE) {
                const tag = child.tagName.toLowerCase();
                if (!allowedTags.includes(tag)) {
                    toRemove.push(child);
                    continue;
                }
                sanitizeAttributes(child, allowedAttrs);
                sanitizeNode(child, allowedTags, allowedAttrs);
            }
            // Text and comment nodes are left; comments are removed by not preserving them
        }

        for (const rem of toRemove) {
            // Replace disallowed element with its text content to avoid losing content
            const tn = document.createTextNode(rem.textContent || '');
            node.replaceChild(tn, rem);
        }
    }

    function defaultAllowed() {
        return [
            'p', 'br', 'strong', 'b', 'em', 'i', 'u', 's', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6',
            'ul', 'ol', 'li', 'blockquote', 'hr', 'a', 'img', 'span', 'div',
            'table', 'tr', 'td', 'th', 'thead', 'tbody', 'tfoot', 'caption',
            'figure', 'figcaption', 'video', 'source', 'sub', 'sup'
        ];
    }

    function defaultAttrs() {
        return {
            'a': ['href', 'target', 'rel', 'title'],
            'img': ['src', 'alt', 'title', 'width', 'height', 'style'],
            'span': ['style', 'class'],
            'div': ['style', 'class'],
            'video': ['src', 'width', 'height', 'controls', 'autoplay', 'loop', 'muted'],
            'source': ['src', 'type'],
            'figure': ['contenteditable', 'class'],
            'figcaption': ['contenteditable'],
            'td': ['colspan', 'rowspan'],
            'th': ['colspan', 'rowspan']
        };
    }

    function sanitize(html, config) {
        try {
            if (!html) return '';
            const allowedTags = (config && config.ALLOWED_TAGS) ? config.ALLOWED_TAGS : defaultAllowed();
            // Accept either DOMPurify's ALLOWED_ATTR or ALLOWED_ATTRS from callers
            const allowedAttrs = (config && (config.ALLOWED_ATTRS || config.ALLOWED_ATTR)) ? (config.ALLOWED_ATTRS || config.ALLOWED_ATTR) : defaultAttrs();

            const temp = document.createElement('div');
            // Use innerHTML to parse; then walk and remove unsafe pieces
            temp.innerHTML = html;

            // Remove script/style/meta/link/iframe elements aggressively
            const black = ['script', 'style', 'link', 'meta', 'object', 'embed', 'iframe'];
            for (const b of black) {
                const list = temp.getElementsByTagName(b);
                for (let i = list.length - 1; i >= 0; i--) {
                    const node = list[i];
                    node.parentNode && node.parentNode.removeChild(node);
                }
            }

            sanitizeNode(temp, allowedTags, allowedAttrs);
            return temp.innerHTML;
        } catch (e) {
            console && console.warn && console.warn('Local DOMPurify shim sanitize failed', e);
            return '';
        }
    }

    // Expose minimal DOMPurify-like API
    window.DOMPurify = {
        sanitize: sanitize
    };

})(window);
